class Bad {
    fun build(): String {
        val sb = StringBuilder()
        sb.append("hello").append(" world")
        return sb.toString()
    }
}

class Bad {
    fun build(): String {
        val sb = StringBuilder()
        sb.append("a").append("b").append("c")
        return sb.toString()
    }
}

class Good {
    fun build(): String {
        val sb = StringBuilder()
        sb.append("hello world")
        return sb.toString()
    }
}

class Good {
    fun build(name: String): String {
        val sb = StringBuilder()
        sb.append("hello ").append(name)
        return sb.toString()
    }
}
